package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.Test;

class JsonElementTest {

  @Test
  void getAsJsonObject_whenIsJsonObjectTrue_returnsThisAsJsonObject() {
    JsonElement jsonElement = mock(JsonElement.class);
    when(jsonElement.isJsonObject()).thenReturn(true);
    // Cast to JsonObject to simulate that 'this' is actually a JsonObject instance
    JsonObject jsonObject = mock(JsonObject.class);
    // Use spy to allow partial mocking
    JsonElement spyElement = spy(jsonElement);
    doReturn(true).when(spyElement).isJsonObject();

    // We need to simulate that the object is a JsonObject instance
    // since getAsJsonObject casts 'this' to JsonObject
    // So we create an anonymous subclass of JsonElement that is also a JsonObject
    JsonElement element = new JsonObject() {
      @Override
      public boolean isJsonObject() {
        return true;
      }
      @Override
      public JsonElement deepCopy() {
        return this;
      }
    };

    JsonObject result = element.getAsJsonObject();
    assertSame(element, result);
  }

  @Test
  void getAsJsonObject_whenIsJsonObjectFalse_throwsIllegalStateException() {
    JsonElement element = new JsonElement() {
      @Override
      public boolean isJsonObject() {
        return false;
      }
      @Override
      public JsonElement deepCopy() {
        return this;
      }
      @Override
      public String toString() {
        return "mockedElement";
      }
    };

    IllegalStateException exception = assertThrows(IllegalStateException.class, element::getAsJsonObject);
    assertEquals("Not a JSON Object: mockedElement", exception.getMessage());
  }
}
